import{_,o as t,c as e,ae as a}from"./chunks/framework.Bn0jkBmj.js";const u=JSON.parse('{"title":"为省1万元，家政老板熬成“夜半码农”","description":null,"frontmatter":{"title":null,"description":null},"headers":[],"relativePath":"scl/为省1万元，家政老板熬成“夜半码农”.md","filePath":"scl/为省1万元，家政老板熬成“夜半码农”.md"}'),o={name:"scl/为省1万元，家政老板熬成“夜半码农”.md"};function r(l,p,n,s,c,i){return t(),e("div",null,[...p[0]||(p[0]=[a('<h1 id="为省1万元-家政老板熬成-夜半码农" tabindex="-1">为省1万元，家政老板熬成“夜半码农” <a class="header-anchor" href="#为省1万元-家政老板熬成-夜半码农" aria-label="Permalink to &quot;为省1万元，家政老板熬成“夜半码农”&quot;">​</a></h1><p>上次说到， 我这老爷电脑，啃不动—— 那6000多条哭声录音。</p><p>我｜编程小白｜家政老兵， 真的舍不得、也没有决心， 购买英伟达显卡。</p><p>一天，和搞IT的邻居等电梯， 闲聊中意外得知： 网上有限时免费的云端算力☁️。</p><p>我赶紧试了试，果然能用； 但是，白天用的人太多了， 老是断线，甚至连不上。</p><p>没办法， 只能错峰、夜间去蹭网。</p><p>于是，在接下来夜晚， 我边啃天书般的教材， 边敲代码编程💻。</p><p>当窗外的银行霓虹灯熄灭了， 我知道，可以去蹭算力了，</p><p>当楼道的电梯彻底安静， 我知道，已经是第二天了，</p><p>当送奶工的三轮车， “哐当哐当”从楼下路过， 再传来扫马路的“唰喇”声时， 我知道，应该是凌晨4点了。</p><p>有时，我会到阳台， 松缓一下干涩的眼睛，</p><p>望着远方 零星亮灯的窗户， 我总会胡乱猜想，</p><p>可能在一扇窗口里， 有位宝妈正坐在床上、披着棉睡衣， 喃喃地哄着哭闹不止😭的小宝贝……</p><p>这时候，老婆往往会起床， 边给我冲麦片， 边对我嘟囔“没苦硬吃”，</p><p>她哪里知道—— 满屏英文字符中，那闪闪动、往前拱的进度条， 比麦片更香……</p><p>就这样，熬过近170天， 硬生生，把自己熬成“夜半码农”， 把进度条，熬出了绿色的&quot;100％&quot;，</p><p>省下了大1万元， 刚向老婆炫耀了几天， 还没有捂热，就要“割肉”……</p>',17)])])}const m=_(o,[["render",r]]);export{u as __pageData,m as default};
